#!/bin/bash
# Populate all essential pages with rich Puck content blocks
# Run from project root: bash scripts/populate-pages.sh
# Requires: wrangler CLI configured with Cloudflare credentials

set -e

API_DIR="$(cd "$(dirname "$0")/../packages/api" && pwd)"
cd "$API_DIR"

update_page() {
  local slug="$1"
  local content_blocks="$2"
  local title="$3"

  echo "Updating page: $slug"

  # Escape single quotes in content_blocks for SQL
  local escaped_blocks
  escaped_blocks=$(echo "$content_blocks" | sed "s/'/''/g")

  local sql="UPDATE pages SET content_blocks = '${escaped_blocks}', editor_version = 'puck', updated_at = datetime('now') WHERE slug = '${slug}'"

  npx wrangler d1 execute livskompass-db --command "$sql" --remote 2>&1 | tail -1

  if [ -n "$title" ]; then
    local escaped_title
    escaped_title=$(echo "$title" | sed "s/'/''/g")
    npx wrangler d1 execute livskompass-db --command "UPDATE pages SET title = '${escaped_title}' WHERE slug = '${slug}'" --remote 2>&1 | tail -1
  fi
}

echo "=== Populating Essential Pages ==="
echo ""

# ============================================================
# 1. HOMEPAGE (home-2)
# ============================================================
echo "--- 1/18: Homepage ---"
update_page "home-2" '{"content":[{"type":"Hero","props":{"preset":"centered","heading":"Livskompass","subheading":"ACT och mindfulness \u2013 verktyg f\u00f6r ett rikare liv. Utbildningar, material och \u00f6vningar med leg. psykolog Fredrik Livheim.","bgStyle":"gradient","ctaPrimaryText":"Se utbildningar","ctaPrimaryLink":"/utbildningar","ctaSecondaryText":"L\u00e4s om ACT","ctaSecondaryLink":"/act","image":"","backgroundImage":"","overlayDarkness":"medium","id":"hero-home"}},{"type":"FeatureGrid","props":{"heading":"Tre v\u00e4gar till f\u00f6r\u00e4ndring","subheading":"Livskompass bygger p\u00e5 evidensbaserade metoder f\u00f6r att hantera stress, \u00f6ka psykisk flexibilitet och leva ett mer meningsfullt liv.","columns":3,"items":[{"icon":"heart","title":"ACT \u2013 Acceptance and Commitment Therapy","description":"En modern KBT-metod med starkt forskningsst\u00f6d. L\u00e4r dig hantera sv\u00e5ra tankar och k\u00e4nslor, och fokusera p\u00e5 det som verkligen \u00e4r viktigt f\u00f6r dig."},{"icon":"sparkles","title":"Mindfulness \u2013 Medveten n\u00e4rvaro","description":"\u00d6vningar i medveten n\u00e4rvaro som hj\u00e4lper dig vara h\u00e4r och nu. Tillg\u00e4ngligt via app, CD-skivor och kurser."},{"icon":"users","title":"Utbildningar och kurser","description":"Gruppledarutbildningar, f\u00f6rel\u00e4sningar och booster-dagar. F\u00f6r dig som vill anv\u00e4nda ACT i ditt yrke eller ditt eget liv."}],"style":"cards","id":"features-home"}},{"type":"CourseList","props":{"heading":"Kommande utbildningar","maxItems":3,"columns":2,"showBookButton":true,"compactMode":false,"id":"courses-home"}},{"type":"Testimonial","props":{"quote":"ACT-utbildningen gav mig konkreta verktyg som jag direkt kunde anv\u00e4nda i mitt arbete med klienter. Fredriks s\u00e4tt att undervisa \u00e4r b\u00e5de varmt och professionellt.","author":"Kursdeltare","role":"Leg. psykolog, gruppledarutbildning 2025","avatar":"","style":"featured","id":"testimonial-home"}},{"type":"PostGrid","props":{"heading":"Senaste nyheterna","subheading":"","count":3,"columns":3,"showImage":true,"showExcerpt":true,"showDate":true,"cardStyle":"default","id":"posts-home"}},{"type":"CTABanner","props":{"heading":"Redo att ta n\u00e4sta steg?","description":"Boka din plats p\u00e5 n\u00e4sta gruppledarutbildning eller kontakta oss f\u00f6r mer information.","buttonText":"Se alla utbildningar","buttonLink":"/utbildningar","backgroundColor":"primary","alignment":"center","id":"cta-home"}}],"root":{"props":{}},"zones":{}}' "Startsida"

# ============================================================
# 2. ACT (hub page)
# ============================================================
echo "--- 2/18: ACT hub ---"
update_page "act" '{"content":[{"type":"Hero","props":{"preset":"minimal","heading":"ACT \u2013 Acceptance and Commitment Therapy","subheading":"En evidensbaserad psykologisk metod som hj\u00e4lper dig hantera stress, \u00f6ka din psykiska flexibilitet och leva i linje med dina v\u00e4rderingar.","bgStyle":"gradient","ctaPrimaryText":"","ctaPrimaryLink":"","ctaSecondaryText":"","ctaSecondaryLink":"","image":"","backgroundImage":"","overlayDarkness":"medium","id":"hero-act"}},{"type":"RichText","props":{"content":"<h2>Vad \u00e4r ACT?</h2><p>ACT (Acceptance and Commitment Therapy) \u00e4r en modern form av kognitiv beteendeterapi (KBT) med starkt vetenskapligt st\u00f6d. Metoden utvecklades av Steven C. Hayes och har sedan dess f\u00e5tt brett genomslag inom psykologin v\u00e4rlden \u00f6ver.</p><p>I st\u00e4llet f\u00f6r att f\u00f6rs\u00f6ka eliminera sv\u00e5ra tankar och k\u00e4nslor handlar ACT om att l\u00e4ra sig <strong>acceptera</strong> det som \u00e4r sv\u00e5rt, vara <strong>n\u00e4rvarande</strong> i nuet och <strong>agera</strong> utifr\u00e5n det som \u00e4r viktigt f\u00f6r dig \u2013 dina v\u00e4rderingar.</p><p>Livskompass erbjuder ett v\u00e4lbepr\u00f6vat ACT-gruppformat som har utvecklats och testats i svenska sammanhang sedan 2005. Formatet anv\u00e4nds idag av hundratals utbildade gruppledare i Sverige och Norden.</p>","maxWidth":"medium","id":"intro-act"}},{"type":"PageCards","props":{"heading":"Utforska ACT","parentSlug":"act","manualPages":[{"title":"Vad \u00e4r ACT?","description":"En grundlig introduktion till Acceptance and Commitment Therapy \u2013 teori, forskning och praktik.","slug":"vad-ar-act","icon":""},{"title":"Om detta gruppformat","description":"L\u00e4s om det svenska ACT-gruppformatet som utvecklats av Fredrik Livheim och som anv\u00e4nds av hundratals gruppledare.","slug":"om-detta-gruppformat-av-act","icon":""}],"columns":2,"showDescription":true,"style":"card","id":"pages-act"}},{"type":"StatsCounter","props":{"items":[{"value":"20","label":"\u00c5rs forskning och utveckling","prefix":"","suffix":"+"},{"value":"500","label":"Utbildade gruppledare","prefix":"","suffix":"+"},{"value":"15","label":"Vetenskapliga publikationer","prefix":"","suffix":""},{"value":"50000","label":"Deltagare i ACT-grupper","prefix":"","suffix":"+"}],"columns":4,"style":"default","id":"stats-act"}},{"type":"CTABanner","props":{"heading":"Vill du l\u00e4ra dig ACT?","description":"Gruppledarutbildningen ger dig kompetens att leda ACT-grupper i ditt eget arbete.","buttonText":"Se utbildningar","buttonLink":"/utbildningar","backgroundColor":"primary","alignment":"center","id":"cta-act"}}],"root":{"props":{}},"zones":{}}' "ACT"

# ============================================================
# 3. VAD ÄR ACT?
# ============================================================
echo "--- 3/18: Vad är ACT? ---"
update_page "vad-ar-act" '{"content":[{"type":"PageHeader","props":{"heading":"Vad \u00e4r ACT?","subheading":"Acceptance and Commitment Therapy \u2013 en evidensbaserad metod f\u00f6r psykisk h\u00e4lsa","alignment":"left","size":"large","showDivider":true,"breadcrumbs":[{"label":"ACT","href":"/act"},{"label":"Vad \u00e4r ACT?","href":""}],"id":"header-vad-ar-act"}},{"type":"RichText","props":{"content":"<h2>En modern KBT-metod</h2><p>ACT (uttalas som det engelska ordet \u00abact\u00bb) st\u00e5r f\u00f6r <strong>Acceptance and Commitment Therapy</strong>. Det \u00e4r en modern form av kognitiv beteendeterapi (KBT) som utvecklats sedan 1980-talet och idag har starkt vetenskapligt st\u00f6d f\u00f6r en rad olika tillst\u00e5nd.</p><h2>Sex k\u00e4rnprocesser</h2><p>ACT bygger p\u00e5 sex samverkande processer som tillsammans \u00f6kar <em>psykologisk flexibilitet</em> \u2013 f\u00f6rm\u00e5gan att vara \u00f6ppen f\u00f6r sina upplevelser och handla utifr\u00e5n sina v\u00e4rderingar:</p><ol><li><strong>Acceptans</strong> \u2013 Att \u00f6ppna sig f\u00f6r sv\u00e5ra k\u00e4nslor ist\u00e4llet f\u00f6r att k\u00e4mpa emot dem</li><li><strong>Defusion</strong> \u2013 Att kunna ta ett steg tillbaka fr\u00e5n sina tankar och se dem som just tankar</li><li><strong>N\u00e4rvaro</strong> \u2013 Att vara medvetet n\u00e4rvarande i nuet ist\u00e4llet f\u00f6r att fastna i det f\u00f6rflutna eller framtiden</li><li><strong>Sj\u00e4lvet som kontext</strong> \u2013 Att observera sina upplevelser utan att identifiera sig med dem</li><li><strong>V\u00e4rderingar</strong> \u2013 Att utforska vad som verkligen \u00e4r viktigt f\u00f6r en i livet</li><li><strong>Engagerat handlande</strong> \u2013 Att ta konkreta steg i riktning mot sina v\u00e4rderingar</li></ol><h2>F\u00f6r vem?</h2><p>ACT har visat sig effektivt vid en rad tillst\u00e5nd, bland annat:</p><ul><li>Stress och utmattning</li><li>Depression och \u00e5ngest</li><li>Kronisk sm\u00e4rta</li><li>Missbruk och beroende</li><li>Arbetsrelaterad oh\u00e4lsa</li><li>Allm\u00e4n livsf\u00f6rb\u00e4ttring och personlig utveckling</li></ul><p>Metoden anv\u00e4nds idag inom h\u00e4lso- och sjukv\u00e5rd, f\u00f6retagsh\u00e4lsov\u00e5rd, skola, socialtj\u00e4nst och kriminalv\u00e5rd.</p>","maxWidth":"medium","id":"content-vad-ar-act"}},{"type":"Accordion","props":{"heading":"Vanliga fr\u00e5gor om ACT","items":[{"question":"Vad skiljer ACT fr\u00e5n traditionell KBT?","answer":"Traditionell KBT fokuserar ofta p\u00e5 att f\u00f6r\u00e4ndra inneh\u00e5llet i negativa tankar. ACT handlar ist\u00e4llet om att f\u00f6r\u00e4ndra sitt f\u00f6rh\u00e5llande till tankar och k\u00e4nslor \u2013 att kunna ha dem utan att styras av dem."},{"question":"Beh\u00f6ver man vara psykiskt sjuk f\u00f6r att ha nytta av ACT?","answer":"Nej, ACT \u00e4r lika relevant f\u00f6r allm\u00e4n livsf\u00f6rb\u00e4ttring som f\u00f6r behandling av specifika tillst\u00e5nd. M\u00e5nga anv\u00e4nder ACT f\u00f6r att hantera vardagsstress b\u00e4ttre och leva mer i linje med sina v\u00e4rderingar."},{"question":"Vad inneb\u00e4r \u00abacceptans\u00bb i ACT?","answer":"Acceptans i ACT handlar inte om att ge upp eller resignera. Det handlar om att sluta k\u00e4mpa mot det som inte g\u00e5r att f\u00f6r\u00e4ndra (som sv\u00e5ra k\u00e4nslor och tankar) och ist\u00e4llet l\u00e4gga sin energi p\u00e5 meningsfulla handlingar."},{"question":"Finns det forskning som st\u00f6djer ACT?","answer":"\u00d6ver 1 000 randomiserade kontrollerade studier har publicerats om ACT. I Sverige har specifikt det gruppformat som Livskompass erbjuder studerats i flera vetenskapliga studier med goda resultat."}],"defaultOpen":"none","style":"bordered","id":"faq-vad-ar-act"}},{"type":"ButtonGroup","props":{"buttons":[{"text":"Se utbildningar","link":"/utbildningar","variant":"primary"},{"text":"L\u00e4s om forskningen","link":"/forskning-pa-metoden","variant":"outline"}],"alignment":"center","direction":"horizontal","size":"medium","id":"buttons-vad-ar-act"}}],"root":{"props":{}},"zones":{}}' ""

