echo "--- 13/18: Forskning hub ---"
update_page "forskning-pa-metoden" '{"content":[{"type":"Hero","props":{"preset":"minimal","heading":"Forskning p\u00e5 metoden","subheading":"Det ACT-gruppformat som Livskompass erbjuder \u00e4r vetenskapligt utv\u00e4rderat i b\u00e5de svenska och internationella studier.","bgStyle":"gradient","ctaPrimaryText":"","ctaPrimaryLink":"","ctaSecondaryText":"","ctaSecondaryLink":"","image":"","backgroundImage":"","overlayDarkness":"medium","id":"hero-forskning"}},{"type":"RichText","props":{"content":"<p>Evidens och vetenskaplig grund \u00e4r centralt f\u00f6r Livskompass. Det gruppformat vi arbetar med \u2013 <em>Att leva livet fullt ut</em> \u2013 har studerats i flera randomiserade kontrollerade studier (RCT) i svenska och internationella sammanhang.</p><p>Fredrik Livheims doktorsavhandling vid Uppsala universitet bidrog med viktig kunskap om hur ACT i grupp kan fr\u00e4mja psykisk h\u00e4lsa och minska stress.</p>","maxWidth":"medium","id":"intro-forskning"}},{"type":"StatsCounter","props":{"items":[{"value":"15","label":"Vetenskapliga publikationer","prefix":"","suffix":"+"},{"value":"3","label":"Randomiserade kontrollerade studier","prefix":"","suffix":""},{"value":"1500","label":"Forskningsdeltagare","prefix":"","suffix":"+"},{"value":"2005","label":"\u00c5r av forskning och utveckling","prefix":"Sedan ","suffix":""}],"columns":4,"style":"bordered","id":"stats-forskning"}},{"type":"PageCards","props":{"heading":"Forsknings\u00f6versikt","parentSlug":"","manualPages":[{"title":"Svensk forskning","description":"Studier p\u00e5 det svenska ACT-gruppformatet, inklusive Fredrik Livheims doktorsavhandling.","slug":"forskning-pa-detta-gruppformat-av-act-i-sverige","icon":""},{"title":"Internationell forskning","description":"\u00d6versikt av internationella studier p\u00e5 liknande ACT-gruppformat.","slug":"internationell-forskning-pa-ett-liknande-gruppformat-av-act","icon":""}],"columns":2,"showDescription":true,"style":"card","id":"pages-forskning"}},{"type":"CTABanner","props":{"heading":"Vill du veta mer?","description":"Kontakta oss f\u00f6r att diskutera forskningen eller f\u00f6r att best\u00e4lla Fredriks avhandling.","buttonText":"Kontakta oss","buttonLink":"/kontakt","backgroundColor":"light","alignment":"center","id":"cta-forskning"}}],"root":{"props":{}},"zones":{}}' ""

