update_page "norge" '{"content":[{"type":"PageHeader","props":{"heading":"Utdanning i ACT \u2013 Norge","subheading":"Gruppelederkurs online for norske fagpersoner","alignment":"left","size":"large","showDivider":true,"breadcrumbs":[{"label":"Utbildningar","href":"/utbildningar"},{"label":"Norge","href":""}],"id":"header-norge"}},{"type":"RichText","props":{"content":"<p>Vi tilbyr gruppelederkurs i ACT-programmet \u00abTid til \u00e5 leve\u00bb for fagpersoner i Norge. Kurset gjennomf\u00f8res online og gir deg kompetanse til \u00e5 lede ACT-grupper i din virksomhet.</p><h2>Innhold</h2><ul><li>Grunnleggende ACT-teori og forskning</li><li>Praktisk trening i \u00e5 lede ACT-\u00f8velser</li><li>Manual og kursmaterialer p\u00e5 norsk</li><li>Veiledning i oppstart av egne grupper</li></ul><h2>M\u00e5lgruppe</h2><p>Kurset er rettet mot fagpersoner innen helse, sosial, skole og arbeidsliv som \u00f8nsker \u00e5 bruke ACT i gruppetilbud.</p>","maxWidth":"medium","id":"content-norge"}},{"type":"CTABanner","props":{"heading":"Interesse?","description":"Kontakt oss for mer informasjon om neste kurs.","buttonText":"Kontakt","buttonLink":"/kontakt","backgroundColor":"primary","alignment":"center","id":"cta-norge"}}],"root":{"props":{}},"zones":{}}' ""

